import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,a as t}from"./app-0abf0765.js";const n={},l=t(`<h1 id="adatbazis-hasznalata" tabindex="-1"><a class="header-anchor" href="#adatbazis-hasznalata" aria-hidden="true">#</a> Adatbázis használata</h1><div class="hint-container note"><p class="hint-container-title">Ennek a témakörnek az a célja, hogy</p><ul><li>megtanuljuk az adatok tárolását az adatbázisban</li><li>megtanuljuk az adatok megjelenítése és kinyírését az adatbázisból</li><li>megtnauljuk az adatok frissítését és törlését</li></ul></div><p>Ha az adatbázisod üres az olyan mintha lenne egy üres süteményes dobozod - semmit nem nyersz vele 😄. Emellett egy üres adatbázisban keresni sem érdekesebb vagy hasznosabb, mint az üres sütisdobozban kotorászni. Az adatbázisodnak csak a benne lévő információkkal együtt veheted hasznát.</p><p>Az adatbázisoknak tudniuk kell fogadni az adatokat, hogy eltárolhassák azokat és tudniuk kell kérésre adatokat szolgáltatni. A <code>VasarloiRendelesInformaciok</code> adatbázisnak például melyről a korábbi fejezetekben már olvashattál tudnia kell fogadni a vásárlók és rendeléseik információit és amikor azokat lekéred tőle át kell tudnia adni a benne tárolt információkat. Ha például tudni szeretnéd egy konkrét vásárló címét vagy hogy mikor adtak le egy konkrét rendelést, az adatbázisnak át kell tudnia adni ezeket az információkat, amikor lekéred őket.</p><div class="hint-container warning"><p class="hint-container-title">Az SQL adatbázisod négyféle kérésre válaszol:</p><p><strong>Információk beszúrása:</strong> Új sor hozzáadása egy táblához.</p><p><strong>Információk lekérése:</strong> Az adatok megjelenítése. Ezzel a kéréssel az adatbázisból nem távolítod el az adatokat.</p><p><strong>Információk frissítése:</strong> Egy meglévő sor információinak módosítása. Ezzel egy meglévő sor üres mezőibe is szúrhatsz be információkat.</p><p><strong>Információk törlése:</strong> Adatok törlése az adatbázisból.</p></div><h3 id="informaciok-beszurasa-az-adatbazisba" tabindex="-1"><a class="header-anchor" href="#informaciok-beszurasa-az-adatbazisba" aria-hidden="true">#</a> Információk beszúrása az adatbázisba</h3><p>Minden adatbázisba kellenek adatok. Elhelyezheted például az adataidat az adatbázisodban azért, hogy a felhasználóid láthassák őket vagy létrehozhatsz üres adatbázist, hogy a felhasználóid feltöltsék adatokkal. Ha az adataid még csak papíron vannak meg akkor közvetlenül is beszúrhatod őket egy adatbázisba SQL utasításban. Ha azonban rengeteg adatod van akkor ez a folyamat felettébb unalmas lehet és rengeteget kell gépelned hozzá. Tegyük fel, hogy 1000 olyan termékről vannak információid melyeket fel kell venned az adatbázisodba.<br> Ha feltesszük, hogy úgy tudsz gépelni, mint a villám és így percenként be tudsz szúrni egy sort ez még akkor is 16 órányi szélsebes gépelést jelent - vagyis szélsebes szerkesztést, de mindegy 🤷‍♂️. Meg lehet csinálni, de nem túl szívderítő. Másrészt viszont tegyük fel, hogy egy szervezet 5000 tagját kell felvinned egy adatbázisba, és hogy minden egyes tagot öt percig tart beszúrni 🙄. Ez így már több mint 400 órányi gépelés - erre meg kinek van ideje 👀 ?</p><p>A <code>LOAD</code> SQL utasítással egy nagyméretű szöveges fájlból olvashatsz be adatokat. Szóval, ha már megvannak az adataid egy fájlban akkor nem kell mindent újra begépelned! Még ha az adatok nem is olyan szöveges fájl formátumban vannak - <em>Excel, Access</em> - általában átalakíthatod őket, melyet aztán beolvashatsz az adatbázisodba.</p><h3 id="adatok-beszurasa-soronkent" tabindex="-1"><a class="header-anchor" href="#adatok-beszurasa-soronkent" aria-hidden="true">#</a> Adatok beszúrása soronként</h3><p>Ha kevés adatod van akkor beszúrhatod a sorokat a tábládba egyesével. Az <code>INSERT</code> utasítással adhatsz hozzá egy sort az adatbázisodhoz. Ez az utasítás megmondja az SQL-nek, hogy melyik táblába vegye fel az új sort, és hogy milyen értékeket tegyen az egyes mezőkbe az új sorban.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> tablanev <span class="token punctuation">(</span>oszlopnev1<span class="token punctuation">,</span> oszlopnev2<span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">,</span> oszlopnevN<span class="token punctuation">)</span>
<span class="token keyword">VALUES</span> <span class="token punctuation">(</span>ertek1<span class="token punctuation">,</span> ertek2<span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">,</span> ertekN<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">Az INSERT utasításra a következő szabályok vonatkoznak:</p><p><strong>Az értékeket ugyanabban a sorrendben kell megadnod, amelyben az oszlopneveket megadtad.</strong> Az értékek listájában szereplő első értéket abba az oszlopba szúrja be, mely első helyen szerepel az oszlopok listájában, a második érték az értékek listájában a másodikként említett oszlopba kerül és így tovább.</p><p><strong>Használhatsz teljes vagy részleges oszloplistát.</strong> Nem kell felsorolnod az összes oszlopot. Az olyan oszlopokba, melyek nem szerepelnek a listán az alapértelmezett értékük kerül, vagy pedig üresen maradnak, ha nincs hozzájuk alapértelmezett érték megadva.</p><p><strong>Nem kötelező megadnod az oszloplistát.</strong> Ha minden egyes oszlophoz adsz meg értéket, akkor egyáltalán nem kell felsorolnod az oszlopokat. Ha nem adsz meg oszloplistát akkor az SQL minden egyes oszlophoz várni fog egy értéket, abban a sorrendben melyben megjelennek a táblában.</p><p><strong>Az oszloplistának és az értéklistának egyeznie kell.</strong> Minden egyes oszlophoz melyet felsorolsz meg kell adnod egy értéket, különben egy ehhez hasonló hibaüzenetet fogsz kapni: <code>Column count doesn&#39;t match value count</code>.</p></div><h3 id="adatbazis-adatainak-megnezese" tabindex="-1"><a class="header-anchor" href="#adatbazis-adatainak-megnezese" aria-hidden="true">#</a> Adatbázis adatainak megnézése</h3><p>Miután felvitted az adatokat az adatbázisodba, lehet, hogy végig szeretnéd böngészni azokat és ellenőrizni szeretnéd, hogy a felvitt adatok megfelelőnek tűnnek-e vagy tudni szeretnéd, milyen típusú adatok vannak az adatbázisban. Az adatok áttekintésével egyszerű információkat is megtudhatsz az adatbázisodról, például hogy hány rekordot tartalmaz. A következő lekérdezéssel egy tábla összes adatát lekérdezheted:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ezzel a lekérdezéssel minden adatot kinyerhetsz egy táblából. Így megtudhatod, hogy mennyi rekord van a táblában és ha végig böngészed a kimenetét, kapsz egy általános képet az adatokról. Azt, hogy pontosan hány adatrekord van egy táblában a következő lekérdezéssel határozhatod meg:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">FROM</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ez a lekérdezés az adott táblában lévő rekordok számát adja vissza.</p><p>Az egyetlen ok, amiért információkat tárolsz egy adatbázisban, hogy elérhetőek legyenek amikor szükséged van rájuk. Az adatbázisnak az a célja, hogy megválaszolja a kérdéseidet. Milyen termékeket lehet megvásárolni? Kik a vásárlók? Hány vásárló él Zala megyében? Mit visznek a vásárlók?</p><p>Sok kérdést válaszolhatsz meg úgy, hogy adatokat nyersz ki az adatbázisodból. Ha például meg szeretnéd tudni, hogy hány vásárlód él Zalában, kinyerheted az összes olyan vásárló rekordját akiknél a <code>megye</code> nevű mező értéke <code>Zala</code>. Ha konkrét kérdéseket szeretnél megválaszolni, használd a <code>SELECT</code> lekérdezést. A <code>SELECT</code> lekérdezés segítségével pontos, összetett és részletes kérdéseket is feltehetsz. A lehető legegyszerűbb <code>SELECT</code> lekérdezés a következő:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ez a lekérdezés minden információt kinyer az adott táblából. A csillag (*) egy <em>Joker</em> karakter, mely azt jelenti, hogy minden oszlop. A <code>SELECT</code> lekérdezést ennél sokkal érzékenyebben is beállíthatod. A <code>SELECT</code> lekérdezésben megadott SQL szavak és kifejezések segítségével megjelenítheted pontosan azokat az információkat, melyek választ adnak a kérdésedre.</p><div class="hint-container tip"><p class="hint-container-title">A következő néhány trükkel elérheted, hogy a SELECT lekérdezésed jól teljesítsen:</p><p><strong>Lekérdezheted kizárólag azokat az információkat (oszlopokat), melyekre szükséged van ahhoz, hogy megválaszold a kérdésedet.</strong> Lekérheted például csak a vezeték és keresztneveket és így létrehozhatod a vásárlóid listáját.</p><p><strong>Az információkat lekérdezheted meghatározott sorrendben is.</strong> Kérheted például azt, hogy az információk legyenek rendezve.</p><p><strong>Az információkat lekérdezheted a táblád meghatározott objektumaiból is.</strong> Lekérdezheted például csak azoknak a vásárlóidnak a vezeték és keresztnevét akiknek a címe Békés megyei.</p></div><div class="hint-container warning"><p class="hint-container-title">A SELECT lekérdezéseket beágyazhatod egy másik lekérdezésbe is.</p><p>A beágyazott lekérdezést <em>allekérdezésnek</em> is nevezzük. Használhatsz allekérdezéseket a <code>SELECT</code>, az <code>INSERT</code>, az <code>UPDATE</code> és <code>DELETE</code> utasításokban illetve a <code>SET</code> kulcsszavakban. Egy allekérdezés visszaadhat egyetlen értéket egy sor vagy egy oszlopot vagy egy táblát melyet a külső lekérdezésben felhasználhatsz. A <code>SELECT</code> lekérdezések minden lehetőségét kihasználhatod allekérdezésekben is.</p></div><h3 id="konkret-informaciok-kinyerese-az-adatbazisbol" tabindex="-1"><a class="header-anchor" href="#konkret-informaciok-kinyerese-az-adatbazisbol" aria-hidden="true">#</a> Konkrét információk kinyerése az adatbázisból</h3><p>Ha konkrét információkat szeretnél lekérdezni, sorold fel azokat az oszlopokat, melyek tartalmazzák az információkat, amelyekre szükséged van. Például így:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> oszlopnev1<span class="token punctuation">,</span> oszlopnev2<span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">,</span> oszlopnevN 
<span class="token keyword">FROM</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Ez a lekérdezés az összes sorból visszaadja az információkat de csak a megjelölt oszlopaikból. A következő lekérdezéssel például kinyerheted az összes a <code>Vasarlo</code> táblában megjelenő vásárlód vezeték és keresztnevét a <code>vezeteknev</code> és a <code>keresztnev</code> oszlopból:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> vezeteknev<span class="token punctuation">,</span> keresztnev 
<span class="token keyword">FROM</span> Vasarlo
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Az oszlopokkal matematikai műveleteket is végezhetsz amikor lekérdezed őket. A következő <code>SELECT</code> lekérdezés segítségével például összeadhatsz két oszlopot:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> oszlop1 <span class="token operator">+</span> oszlop2 <span class="token keyword">FROM</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>vagy használhatod a következő lekérdezést is:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> ar<span class="token punctuation">,</span> ar <span class="token operator">*</span> <span class="token number">1.27</span> <span class="token keyword">FROM</span> Leltart
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Az eredményben az árat, illetve a 27 százalékos áfával növelt árat láthatod. Az oszlopokat át is nevezheted a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> ar<span class="token punctuation">,</span> ar <span class="token operator">*</span> <span class="token number">1.27</span> <span class="token keyword">AS</span> bruttoAr <span class="token keyword">FROM</span> Leletar
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Az <code>AS</code> azt mondja meg az SQL-nek, hogy a második lekért oszlopnak adja a <code>bruttoAr</code> nevet. Így a lekérdezés a következő két adatoszlopot adja vissza: <code>ar</code> és <code>bruttoAr</code>. Néhány esetben nem az oszlopban lévő értékekre vagy kíváncsi, hanem magáról az oszlopról szeretnél megtudni valamit. Lehet például, hogy szeretnéd tudni egy oszlop legkisebb vagy legnagyobb értékét. A következő táblázatban láthatsz néhány olyan információt melyeket elérhetsz az egyes oszlopokról.</p><table><thead><tr><th>SQL formátum</th><th>Az információ leírása</th></tr></thead><tbody><tr><td><code>AVG</code></td><td>Az <code>oszlopnev</code> oszlopban lévő értékek átlagát adja vissza.</td></tr><tr><td><code>COUNT</code></td><td>Az olyan sorok darabszámát adja vissza, melyekben az <code>oszlopnev</code> oszlop nem üres.</td></tr><tr><td><code>MAX</code></td><td>Az <code>oszlopnev</code> oszlopban előforduló legnagyobb értéket adja vissza.</td></tr><tr><td><code>MIN</code></td><td>Az <code>oszlopnev</code> oszlopban előforduló legkisebb értéket adja vissza.</td></tr><tr><td><code>SUM</code></td><td>Az <code>oszlopnev</code> oszlopban előforduló összes érték összegét adja vissza.</td></tr></tbody></table><p>Ha például meg szeretnéd keresni a legmagasabb árat a <code>Leltart</code> táblában, azt a következő lekérdezéssel teheted:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token function">MAX</span><span class="token punctuation">(</span>ar<span class="token punctuation">)</span> <span class="token keyword">FROM</span> Leltart
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Az olyan SQL szavakat, mint például a <code>MAX()</code> vagy a <code>SUM()</code>, melyek neve után zárójelpár áll, függvényeknek nevezzük. Az SQL-ben számos függvényt használhatsz azok mellett melyeket a táblázatban is láthatsz. A <code>SELECT</code> lekérdezésekben több mint 100 féle függvényt használhatsz. Vannak függvények melyek a lekérdezett értéket módosítják ilyen például az <code>SQRT()</code> függvény az adott oszlop minden értékének a négyzetgyökét adja vissza.</p><h3 id="adatok-kinyerese-meghatarozott-sorrendben" tabindex="-1"><a class="header-anchor" href="#adatok-kinyerese-meghatarozott-sorrendben" aria-hidden="true">#</a> Adatok kinyerése meghatározott sorrendben</h3><p>Lehet, hogy az adatokat egy adott sorrendben szeretnéd megkapni. A <code>Vasarlo</code> táblában például lehet, hogy szeretnéd a vásárlóidat vezetéknevük szerint ábécésorrendben rendezni vagy esetleg a <code>Leltart</code> táblában szeretnéd a különböző termékeket kategóriák szerint csoportosítani.</p><div class="hint-container tip"><p class="hint-container-title">A SELECT lekérdezésekben az ORDER BY és GROUP BY a sorrendre vannak kihatással, melyben megkapod az adatokat:</p><p><code>ORDER BY</code>: Ezt a kifejezést vedd fel a <code>SELECT</code> lekérdezésedben, ha szeretnéd rendezni az információkat:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> oszlopnev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ekkor az adatokat az <code>oszlopnev</code> szerint rendezheted növekvő sorrendbe. Ha például az <code>oszlopnev</code> a <code>vezeteknev</code>, akkor az adatokat a vezetéknév szerinti ábécésorrendben fogod megkapni.</p><p>Az adatokat csökkenő sorrendbe is rendezheted, ha elhelyezed a <code>DESC</code> kulcsszót az oszlop neve előtt például így:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Vasarlo <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> <span class="token keyword">DESC</span> vezeteknev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>GROUP BY</code>: Ha az információkat csoportosítani szeretnéd, a következő kifejezést használd:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">GROUP</span> <span class="token keyword">BY</span> oszlopnev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ekkor azokat az adatokat, melyeknél az <code>oszlopnev</code> értéke megegyezik, csoportba foglalod. A következő lekérdezéssel például csoportosíthatod azokat a sorokat, melyek ugyanazzal a <code>kategoria</code> értékkel rendelkeznek:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Leltart <span class="token keyword">GROUP</span> <span class="token keyword">BY</span> kategoria
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><p>A <code>GROUP BY</code> és az <code>ORDER BY</code> -t használhatod egyazon lekérdezésben is.</p><h3 id="adatok-kinyerese-meghatarozott-sorokbol" tabindex="-1"><a class="header-anchor" href="#adatok-kinyerese-meghatarozott-sorokbol" aria-hidden="true">#</a> Adatok kinyerése meghatározott sorokból</h3><p>Gyakran előfordul, hogy nem vagy kíváncsi minden információra, mely a tábládban megtalálható, csak meghatározott sorok információit szeretnéd látni.</p><div class="hint-container tip"><p class="hint-container-title">Az információk forrásának meghatározására három SQL kulcs szót alkalmaznak gyakran:</p><p><code>WHERE</code>: Ennek segítségével lekérheted csak azoknak az adatbázis objektumoknak az információit, melyek meghatározott jellemzőkkel rendelkeznek. Lekérheted például azon vásárlók neveit, akik Hajdú-Bihar megyeiek, vagy kilistázhatod csak azokat a termékeket, melyek egy meghatározott ruhakategóriába tartoznak.</p><p><code>LIMIT</code>: Segítségével korlátozhatod azon sorok számát melyekből visszakapod az információkat. Lekérdezheted például csak a tábla első három rekordjának információit.</p><p><code>DISTINCT</code>: Ez azt teszi lehetővé, hogy egyforma sorok közül csak egyetlen sorból kérje le az információkat. Ha például van egy <code>Bejelentkezés</code> táblád akkor lekérheted a <code>felhasznalonev</code> oszlopot, de az ismétlődő értékek kizárásával és így a választ tagonként egyetlen rekordra korlátozhatod.</p></div><h4 id="where-hasznalata" tabindex="-1"><a class="header-anchor" href="#where-hasznalata" aria-hidden="true">#</a> <code>WHERE</code> használata</h4><p>A <code>SELECT</code> utasítás <code>WHERE</code> kulcsszó azt teszi lehetővé számodra, hogy összetett lekérdezéseket valósíthass meg. Tegyük fel például, hogy a főnököd tudni szeretné, hogy hány olyan vásárlód van akiknek a vezetékneve B-vel kezdődik, Debrecenben laknak és a telefonszámukban szerepel 8-as. Ezt a listát egy olyan <code>SELECT</code> utasítással készítheted el a főnöködnek, mely a <code>WHERE</code> kulcsszót tartalmazza.</p><p>A <code>WHERE</code> alapvető formája a következő:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">WHERE</span> kifejezes1 <span class="token operator">AND</span><span class="token operator">|</span><span class="token operator">OR</span> kifejezes2 <span class="token operator">AND</span><span class="token operator">|</span><span class="token operator">OR</span> kifejezes3 <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Itt a <code>kifejezes</code> egy értéket határoz meg, melyet össze kell hasonlítani az adatbázisban tárolt értékekkel. Ekkor csak azok a sorok kerülnek lekérdezésre, melyekben a kifjezésre illeszkedő érték szerepel. Annyi kifejezést használhatsz amennyire csak szükséged van, és mindegyiküket <code>AND</code> vagy <code>OR</code> operátorral kell elválasztanod egymástól. Amikor az <code>AND</code> operátort használod mindkét <code>AND</code> operátorral összekötött kifejezésnek igaznak kell lennie ahhoz, hogy kiválasszunk egy rekordot. Ha pedig az <code>OR</code> operátort használod akkor ahhoz, hogy kiválasszunk egy rekordot elég ha az <code>OR</code> operátorral összekötött kifejezések közül az egyik igaz.</p><table><thead><tr><th>Kifejezés</th><th>Példa</th><th>Eredmény</th></tr></thead><tbody><tr><td>oszlop <code>=</code> ertek</td><td>iranyitoszam <code>=</code> &quot;1234&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam oszlopban az 1234 szerepel.</td></tr><tr><td>oszlop <code>&gt;</code> ertek</td><td>iranyitoszam <code>&gt;</code> &quot;4000&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke 4001 vagy annál nagyobb.</td></tr><tr><td>oszlop <code>&gt;=</code> ertek</td><td>iranyitoszam <code>&gt;=</code> &quot;4000&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke 4000 vagy annál nagyobb.</td></tr><tr><td>oszlop <code>&lt;</code> ertek</td><td>iranyitoszam <code>&lt;</code> &quot;4000&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke 3999 vagy annál kisebb.</td></tr><tr><td>oszlop <code>&lt;=</code> ertek</td><td>iranyitoszam <code>&lt;=</code> &quot;4000&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke 4000 vagy annál kisebb.</td></tr><tr><td>oszlop <code>BETWEEN</code> ertek1 <code>AND</code> ertek2</td><td>iranyitoszam <code>BETWEEN</code> &quot;2000&quot; <code>AND</code> &quot;3000&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke nagyobb mint 1999 és kisebb mint 3001.</td></tr><tr><td>oszlop <code>IN</code> (ertek1, ertek2, ...)</td><td>iranyitoszam <code>IN</code> (&quot;4027&quot;,&quot;8008&quot;)</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke 4027 vagy 8008.</td></tr><tr><td>oszlop <code>NOT IN</code> (ertek1, ertek2, ...)</td><td>iranyitoszam <code>NOT IN</code> (&quot;4027&quot;,&quot;8008&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke bármi lehet ami nem 4027 vagy 8008.</td></tr><tr><td>oszlop <code>LIKE</code> ertek</td><td>iranyitoszam <code>LIKE</code> &quot;9%&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke 9-essel kezdődik.</td></tr><tr><td>oszlop <code>NOT LIKE</code> ertek</td><td>iranyitoszam <code>NOT LIKE</code> &quot;9%&quot;</td><td>Csak azokat a sorokat válogatja ki, melyekben az iranyitoszam értéke nem 9-essel kezdődik.</td></tr></tbody></table><p>A táblázatban szereplő kifejezések közül bármelyeket kombinálhatod <code>AND</code> és <code>OR</code> operátorok segítségével. Néhány esetben zárójelekre is szükséged lesz, hogy egyértelműsítsd a lekérdezés feltételeit. A következő lekérdezéssel például kielégítheted a főnököd sürgős igényét arra, hogy megtaláld az összes olyan vásárlót, akinek a neve B-vel kezdődik, Debrecenben él és a telefonszámában van egy 8-as.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> vezeteknev<span class="token punctuation">,</span> keresztnev
<span class="token keyword">FROM</span> Vasarlo
<span class="token keyword">WHERE</span> vezeteknev <span class="token operator">LIKE</span> <span class="token string">&quot;B%&quot;</span>
    <span class="token operator">AND</span> varos <span class="token operator">=</span> <span class="token string">&quot;Debrecen&quot;</span>
    <span class="token operator">AND</span> telefon <span class="token operator">LIKE</span> <span class="token string">&quot;%8%&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="limit-hasznalata" tabindex="-1"><a class="header-anchor" href="#limit-hasznalata" aria-hidden="true">#</a> <code>LIMIT</code> használata</h4><p>A <code>LIMIT</code> kulcsszó azt határozza meg, hogy hány rekordot lehet visszaadni. A <code>LIMIT</code> kulcsszó formátuma a következő:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">LIMIT</span> szam
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ha az első három olyan vásárlót szeretnéd lekérdezni akik Békés megyében élnek a következő lekérdezést használhatod:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Vasarlo 
<span class="token keyword">WHERE</span> megye <span class="token operator">=</span> <span class="token string">&quot;Bekes&quot;</span> <span class="token keyword">LIMIT</span> <span class="token number">3</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="distinct-hasznalata" tabindex="-1"><a class="header-anchor" href="#distinct-hasznalata" aria-hidden="true">#</a> <code>DISTINCT</code> használata</h4><p>A tábla soraiban egy vagy több oszlopban is előfordulhatnak egyforma értékek. Néhány esetben azonban amikor, lekérdezel egy oszlopot, nem szeretnél minden olyan oszlopot kinyerni, melyek ugyanazt az értéket tartalmazzák. Egy értéket csak egyszer szeretnél kinyerni. Mondjuk van egy táblád, mely termékeket tartalmaz és ebben az egyik mező neve <code>kategoria</code>. Az adatok között nyilván minden kategóriában rengeteg termék szerepel. Tegyük fel, hogy meg szeretnéd jeleníteni az adatbázisban szereplő összes kategória listáját. Egy olyan listát szeretnél melyben minden kategória csak egyszer szerepel. A <code>DISTINCT</code> kulcsszót pont erre a célra találták ki:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> kategoria <span class="token keyword">FROM</span> Termek
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="tobb-tabla-adatainak-egyesitese" tabindex="-1"><a class="header-anchor" href="#tobb-tabla-adatainak-egyesitese" aria-hidden="true">#</a> Több tábla adatainak egyesítése</h3><div class="hint-container tip"><p class="hint-container-title">Két szót használhatsz, ha a SELECT lekérdezésedben két vagy több táblát szeretnél összekapcsolni:</p><p><code>UNION</code>: A sorokat egy vagy több táblából adja vissza, és együtt tárolja őket egymás után egyetlen eredménytáblában. Ha például a lekérdezésed 6 sort ad vissza az egyik táblából és 5 sort egy másik táblából akkor az eredményedben 11 sor lesz.</p><p><code>JOIN</code>: A táblákat egymás mellé helyezi és így kapcsolja össze őket, az információkat pedig mindkét táblából lekérdezi.</p></div><h4 id="union-hasznalata" tabindex="-1"><a class="header-anchor" href="#union-hasznalata" aria-hidden="true">#</a> <code>UNION</code> használata</h4><p>Az <code>UNION</code> kulcsszót akkor használhatod, ha két vagy több lekérdezés eredményét szeretnéd egyesíteni. Minden lekérdezés eredményét hozzáadja az eredménytáblához az azt megelőző lekérdezés eredménye után. A <code>UNION</code> lekérdezés formátuma a következő:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> lekerdezes <span class="token keyword">UNION</span> <span class="token keyword">ALL</span> <span class="token keyword">SELECT</span> lekerdezes
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Annyi <code>SELECT</code> lekérdezést kapcsolhatsz össze, amennyire csak szükséged van. A <code>SELECT</code> utasítás bármely érvényes <code>SELECT</code> kulcsszót tartalmazhat, például <code>WHERE</code>, <code>LIMIT</code> és így tovább.<br> A lekérdezések szabályai a következők:</p><div class="hint-container warning"><p class="hint-container-title">Minden SELECT utasításban egyforma mennyiségű oszlopot kell lekérdezned.</p><p>Az egyes lekérdezésekben kiválasztott oszlopoknak ugyanolyan adattípusai kell legyenek.</p></div><p>Az eredménytábla tartalmazza az első lekérdezés összes sorát, majd ezután a második lekérdezés összes sorát és így tovább. Az eredmény táblában az oszlopok neveit az első <code>SELECT</code> utasítás oszlopnevei adják.</p><p>A <code>SELECT</code> utasítások sorozatával lekérdezheted ugyanannak a táblának a különböző oszlopait az azonban elég ritka, hogy úgy akarsz létrehozni egy új táblát, hogy elhelyezel benne egy oszlopot egy táblából majd egy másik oszlopot ugyanabból a táblából. Sokkal valószínűbb, hogy különböző táblák oszlopait szeretnéd összeilleszteni. Tegyük fel például, hogy van egy táblád melyben azokat a tagokat tartod számon, akik kiléptek egy klubból (<code>RegiTag</code>) és egy másik táblád melyben az aktuális tagok szerepelnek (Tag). Az összes tagot beleértve a korábbi és a jelenlegi tagokat is úgy kaphatod meg, ha a következő lekérdezést használod:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> vezeteknev<span class="token punctuation">,</span> keresztnev
<span class="token keyword">FROM</span> Tag 
<span class="token keyword">UNION</span> <span class="token keyword">ALL</span> <span class="token keyword">SELECT</span> vezeteknev<span class="token punctuation">,</span> keresztnev
<span class="token keyword">FROM</span> RegiTag
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A lekérdezés eredménye az összes jelenlegi tag vezeték és keresztneve majd ezt követően az összes már kilépett tag vezeték és keresztneve lesz.</p><p>Attól függően, hogyan szervezed az adataidat, lehet, hogy lesznek olyan nevek melyek kétszer is előfordulnak. Lehet esetleg, hogy egy tag már kilépett és a neve bekerült a <code>RegiTag</code> táblába - viszont ismét csatlakozott és a neve így bekerült a <code>Tag</code> táblába is. Ha nem szeretnéd, hogy ilyen duplikált értékek forduljanak elő, használd az <code>ALL</code> kulcsszót. Ha megadod, akkor az ismétlődő sorok nem kerülnek bele az eredményedbe.</p><p>Az <code>ORDER BY</code> -t használhatod az egyes SELECT utasításokban, ahogy azt már láttad. Ha azt szeretnéd, hogy az <code>ORDER BY</code> az egész eredményhalmazra érvényes legyen és ne csak arra a lekérdezésre melynek a végén szerepel, akkor használj zárójeleket a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token punctuation">(</span><span class="token keyword">SELECT</span> vezeteknev<span class="token punctuation">,</span> keresztnev
<span class="token keyword">FROM</span> Tag 
<span class="token keyword">UNION</span> <span class="token keyword">ALL</span> <span class="token keyword">SELECT</span> vezeteknev<span class="token punctuation">,</span> keresztnev
<span class="token keyword">FROM</span> RegiTag<span class="token punctuation">)</span> <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> vezeteknev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="osszekapcsolas" tabindex="-1"><a class="header-anchor" href="#osszekapcsolas" aria-hidden="true">#</a> Összekapcsolás</h4><p>Ha egymás mellé helyezve egyesítesz táblákat, azt összekapcsolásnak nevezzük. A táblákat az egy oszlopukban lévő adataik egyezése alapján kapcsolhatod össze - magyarul az alapján az oszlop alapján mely mindkettőjükben megvan. Az egyesített eredménytábla melyet egy összekapcsolásból kapsz mindkét tábla minden oszlopát tartalmazza.<br> Ha például van egy <code>tabla1</code> táblád, melynek két oszlopa van (<code>tag_azon</code> és <code>magassag</code>) és van egy <code>tabla2</code> táblád melynek szintén két oszlopa van (<code>tag_azon</code> és <code>suly</code>) akkor egy összekapcsolással egy a következő négy oszloppal rendelkező táblát kaphatsz: <code>tag_azon</code>, <code>magassag</code>, <code>tag_azon</code> és <code>suly</code>.</p><p>Az összekapcsolás két gyakori típusa a belső összekapcsolás és a külső összekapcsolás.</p><div class="hint-container tip"><p class="hint-container-title">A belső és külső összekapcsolás közötti különbség az eredménytáblában megjelenő rekordok számában van.</p><p><strong>Belső összekapcsolás:</strong> A belső összekapcsolással létrehozott egyesített táblában csak azok a sorok jelennek meg, melyek mindkét táblában megtalálhatóak.</p><p><strong>Külső összekapcsolás:</strong> A külső összekapacsolással létrehozott egyesített táblában minden sor megjelenik amelyik legalább az egyik táblában megvan és azon sorok helyén melyek a másik táblában nem léteznek üres mezők lesznek.</p></div><p>Ha például a <code>tabla1</code> táblában van Józsinak egy rekordja és Sárinak egy rekordja, a <code>tabla2</code> táblában pedig van Sárinak egy rekordja, akkor egy belső összekapcsolásnál csak egyetlen sor jelenik meg: Sári rekordja. Külső kapcsolás esetén azonban két rekord jelenik meg - egy sor Józsihoz és egy sor Sárihoz - habár Józsi sorában üresen marad a <code>suly</code> mező.</p><p>A külső kapcsolás eredménytáblája az egyik tábla minden rekordját tartalmazza. Ha az adott tábla bármely sora hiányzik a másik táblából, akkor a másik táblához tartozó oszlopok üresek lesznek. Az eredmény tábla tartalmát nyilvánvalóan az határozza meg, hogy melyik táblából kerül be az összes sor, melyre a második tábla sorainak illeszkedniük kell. A külső kapcsolás két fajtája határozza meg, hogy melyik tábla állítja be a sorokat, és melyik táblának kell ezekre illeszkednie: ezek a <code>LEFT JOIN</code> és a <code>RIGHT JOIN</code>.</p><p>A belső kapcsoláshoz, illetve két féle külső kapcsoláshoz különböző <code>SELECT</code> utasításokat használhatsz. A következő lekérdezés egy belső kapcsolás:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> oszlopnevek_listaja 
<span class="token keyword">FROM</span> tabla1<span class="token punctuation">,</span> tabla2
<span class="token keyword">WHERE</span> tabla1<span class="token punctuation">.</span>oszlop1 <span class="token operator">=</span> tabla2<span class="token punctuation">.</span>oszlop2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ezek a lekérdezések pedig külső kapcsolások.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> oszlopnevek_listaja
<span class="token keyword">FROM</span> tabla2 <span class="token keyword">LEFT</span> <span class="token keyword">JOIN</span> tabla2 <span class="token keyword">ON</span>
tabla1<span class="token punctuation">.</span>oszlop1 <span class="token operator">=</span> tabla2<span class="token punctuation">.</span>oszlop2

<span class="token keyword">SELECT</span> oszlopnevek_listaja
<span class="token keyword">FROM</span> tabla1 <span class="token keyword">RIGHT</span> <span class="token keyword">JOIN</span> tabla2 <span class="token keyword">ON</span>
tabla1<span class="token punctuation">.</span>oszlop1 <span class="token operator">=</span> tabla2<span class="token punctuation">.</span>oszlop2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <code>tabla1</code> és <code>tabla2</code> mindhárom lekérdezésben az összekapcsolt táblákat jelöli. Kettőnél több táblát is összekapcsolhatsz. Az <code>oszlop1</code> és az <code>oszlop2</code> azoknak az oszlopoknak a nevei, melyek értékeit összehasonlítjuk a táblák összekapcsolásához. A táblák összekapcsolását ezeknek az oszlopoknak az adatai alapján végezhetjük el. Ennek a két oszlopnak megegyezhet a neve vagy különböző neveik is lehetnek, de mindenképpen ugyan olyan típusú adatokat kell tartalmazni.</p><p>A belső és külső kapcsolásokra vegyünk egy példának egy ruhakatalógust mely két táblából áll. Az egyik tábla neve <code>Termek</code>, melyek két oszloppal rendelkezik, ezek a <code>Nev</code> és a <code>Tipus</code> melyekben a következő adatokat találod:</p><table><thead><tr><th>Nev</th><th>Tipus</th></tr></thead><tbody><tr><td>Póló</td><td>ing</td></tr><tr><td>Öltönying</td><td>ing</td></tr><tr><td>Farmernadrág</td><td>nadrág</td></tr></tbody></table><p>A második tábla a <code>Szin</code>, mely két oszloppal rendelkezik, ezek a <code>Nev</code> és a <code>Szin</code>, melyekben a következő adatokat találod:</p><table><thead><tr><th>Nev</th><th>Szin</th></tr></thead><tbody><tr><td>Póló</td><td>fehér</td></tr><tr><td>Póló</td><td>piros</td></tr><tr><td>Papucs</td><td>fekete</td></tr></tbody></table><p>Fel kell tenned egy olyan kérdést, melyhez mindkét táblából szükséged van információkra. Ha a következő lekérdezéssel végrehajtasz egy belső összekapcsolást:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Termek<span class="token punctuation">,</span> Szin <span class="token keyword">WHERE</span> Termek<span class="token punctuation">.</span>Nev <span class="token operator">=</span> Szin<span class="token punctuation">.</span>Nev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>akkor a következő táblát fogod kapni, melyben négy oszlop szerepel, a <code>Nev</code> (a <code>Termek</code> táblából), a <code>Tipus</code>, a <code>Nev</code> (a <code>Szin</code> táblából) és a <code>Szin</code>.</p><table><thead><tr><th>Nev</th><th>Tipus</th><th>Nev</th><th>Szin</th></tr></thead><tbody><tr><td>Póló</td><td>Ing</td><td>Póló</td><td>fehér</td></tr><tr><td>Póló</td><td>Ing</td><td>Póló</td><td>piros</td></tr></tbody></table><p>Figyeld meg, hogy csak a <code>Póló</code> jelenik meg az eredménytáblában - ennek az az oka, hogy csak a <code>Póló</code> van meg mindkét eredeti táblában az összekapcsolás előtt. Ha viszont egy bal oldali külső kapcsolást végzel el a következő lekérdezéssel:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Termek <span class="token keyword">LEFT</span> <span class="token keyword">JOIN</span> Szin <span class="token keyword">ON</span> Termek<span class="token punctuation">.</span>Nev <span class="token operator">=</span> Szin<span class="token punctuation">.</span>Nev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>akkor a következő eredménytáblát fogod kapni ugyanazzal a négy oszloppal - a <code>Nev</code> (a <code>Termek</code> táblából), a <code>Tipus</code>, a <code>Nev</code> (a <code>Szin</code> táblából) és a <code>Szin</code> -. de más sorokkal:</p><table><thead><tr><th>Nev</th><th>Tipus</th><th>Nev</th><th>Szin</th></tr></thead><tbody><tr><td>Póló</td><td>Ing</td><td>Póló</td><td>fehér</td></tr><tr><td>Póló</td><td>Ing</td><td>Póló</td><td>piros</td></tr><tr><td>Öltönying</td><td>Ing</td><td>NULL</td><td>NULL</td></tr><tr><td>Farmernadrág</td><td>Nadrág</td><td>NULL</td><td>NULL</td></tr></tbody></table><p>Ebben a táblában négy rekord szerepel. Az első két sora megegyezik a belső összekapcsolás első két sorával, de két további sora is van - ezek azok a rekordok melyek a <code>Termek</code> táblában a bal oldalon szerepelnek, a <code>Szin</code> táblában viszont nem. Figyeld meg, hogy a <code>Szin</code> táblából származó oszlopok üresek az utolsó két rekordban.</p><p>Harmadrészt tekintsük azt az esetet, amelyben egy jobb oldali külső kapcsolást hajtasz végre a következő utasítással:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Termek <span class="token keyword">RIGHT</span> <span class="token keyword">JOIN</span> Szin <span class="token keyword">ON</span> Termek<span class="token punctuation">.</span>Nev <span class="token operator">=</span> Szin<span class="token punctuation">.</span>Nev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ekkor a következő eredménytáblát fogod kapni, ismét ugyanazzal a négy oszloppal, de megint más sorokkal:</p><table><thead><tr><th>Nev</th><th>Tipus</th><th>Nev</th><th>Szin</th></tr></thead><tbody><tr><td>Póló</td><td>Ing</td><td>Póló</td><td>fehér</td></tr><tr><td>Póló</td><td>Ing</td><td>Póló</td><td>piros</td></tr><tr><td>NULL</td><td>NULL</td><td>Papucs</td><td>fekete</td></tr></tbody></table><p>Figyeld meg, hogy ezen eredmények között a jobb oldalon a <code>Szin</code> tábla összes rekordja szerepel viszont a <code>Termek</code> tábla esetén ez nincs így.<br> Figyeld meg, hogy a <code>Termek</code> tábla oszlopaiban üres mezők szerepelnek, mivel abban nincs a <code>Papucs</code> értékhez tartozó rekord.</p><p>Azokban az összekapcsolásokban, melyekről eddig szó volt a táblákban egyező bejegyzéseket kerestünk. Néha azonban az is hasznos lehet, ha olyan rekordot keresel, melyekhez nem tartozik megfelelő bejegyzés egy másik táblában. Tegyük fel például, hogy tudni szeretnéd, kik azok akik még soha nem jelentkeztek be egy alkalmazásba. Tegyük fel, hogy van egy táblád melyben a tagjaid felhasználónevét tárolod (<code>Tag</code>) és egy másik táblád, melyben a bejelentkezési dátumokat(<code>Bejelentkezés</code>). Felteheted a kérdést úgy, hogy ebből a két táblából kérsz le adatokat. A következő lekérdezés segítségével megtudhatod, hogy mely felhasználóneveknek nincs egyetlen bejegyzése sem a <code>Bejelentkezes</code> táblában:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> felhasznalonev 
<span class="token keyword">FROM</span> Tag <span class="token keyword">LEFT</span> <span class="token keyword">JOIN</span> Bejelentkezes <span class="token keyword">ON</span> Tag<span class="token punctuation">.</span>felhasznalonev <span class="token operator">=</span> Bejelentkzes<span class="token punctuation">.</span>felhasznalonev 
<span class="token keyword">WHERE</span> Bejelentkezes<span class="token punctuation">.</span>felhasznalonev <span class="token operator">IS</span> <span class="token boolean">NULL</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ezzel a lekérdezéssel megkaphatod azoknak a <code>Tag</code> táblában szereplő felhasználóneveknek a listáját, melyek nem fordulnak elő a <code>Bejelentkezes</code> táblában.</p><h3 id="adatok-frissitese-az-adatbazisban" tabindex="-1"><a class="header-anchor" href="#adatok-frissitese-az-adatbazisban" aria-hidden="true">#</a> Adatok frissítése az adatbázisban</h3><p>Ha módosítod egy adatbázis meglévő információit, azt az információk frissítésének nevezzük. Lehet például, hogy módosítanod kell egy vásárló címét, mert elköltözött vagy fel kell venned egy telefonszámot, mert amikor eredetileg megadtad azt az információt ezt a mezőt üresen hagytad.</p><p>Az <code>UPDATE</code> utasítás elég egyértelmű:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">UPDATE</span> tablanev 
<span class="token keyword">SET</span> oszlop<span class="token operator">=</span>ertek
<span class="token keyword">WHERE</span> feltetel
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <code>SET</code> -ben fel kell sorolnod az oszlopokat, melyeket frissíteni akarsz és meg kell adnod az új értékeket, melyeket be szeretnél szúrni. Egy utasításban add meg az összes olyan oszlopot, melyet módosítani szeretnél. <code>WHERE</code> záradék nélkül az oszlop vagy oszlopok értéke minden egyes rekordban módosulna. Ha viszont megadsz egy <code>WHERE</code> záradékot, akkor ezzel meghatározhatod, hogy mely rekordokat szeretnéd frissíteni. Ha például szeretnél egy címet frissíteni a <code>Vasarlo</code> táblában, használd a következő utasítást:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">UPDATE</span> Vasarlo <span class="token keyword">SET</span> utca<span class="token operator">=</span><span class="token string">&quot;Budapesti krt. 123&quot;</span>
                   telefon<span class="token operator">=</span><span class="token string">&quot;555-555-555&quot;</span>
              <span class="token keyword">WHERE</span> vezeteknev<span class="token operator">=</span><span class="token string">&quot;Ceglédi&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="adatok-torlese-az-adatbazisbol" tabindex="-1"><a class="header-anchor" href="#adatok-torlese-az-adatbazisbol" aria-hidden="true">#</a> Adatok törlése az adatbázisból</h3><p>Ahhoz, hogy naprakészen tarthasd az adatbázisodat, törölnöd kell azokat az adatokat, melyek fölött eljárt az idő. Légy azonban nagyon óvatos az információk törlésével. Ha törlöd az adatokat, akkor örökre elvesznek. Nem tudod visszaállítani őket. Egy táblából törölhetsz egy sort vagy egy oszlopot, de törölheted az egész táblát vagy adatbázist is és kezdhetsz minden elölről.</p><p>A következő utasítással törölhetsz egy sort egy táblából a <code>DELETE</code> utasítás segítségével:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> tablanev <span class="token keyword">WHERE</span> feltetel
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ha <code>WHERE</code> feltétel nélkül használod a <code>DELETE</code> utasítást akkor a tábla minden adatát törölni fogod. Egy táblából a következőképpen törölhetsz egy oszlopot az <code>ALTER</code> utasítással:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> tablanev <span class="token keyword">DROP</span> oszlopnev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Egy egész táblát vagy adatbázist pedig a következőkkel távolíthatsz el:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> tablanev <span class="token keyword">DROP</span> oszlopnev

<span class="token keyword">DROP</span> <span class="token keyword">DATABASE</span> adatbazisnev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,123),o=[l];function d(k,r){return a(),s("div",null,o)}const c=e(n,[["render",d],["__file","lesson3.html.vue"]]);export{c as default};
